from abc import ABC, abstractmethod
from typing import Dict, Type, Tuple, Optional
from dataclasses import dataclass

# Algorithm identifiers
class AlgorithmID:
    ML_DSA_44 = "ML-DSA-44"
    ML_DSA_65 = "ML-DSA-65"
    ML_DSA_87 = "ML-DSA-87"
    ML_KEM_512 = "ML-KEM-512"
    ML_KEM_768 = "ML-KEM-768"
    FN_DSA_512 = "FN-DSA-512"
    # Add more as needed

# Abstract interfaces
class SignatureScheme(ABC):
    """Algorithm-agnostic signature interface."""

    @property
    @abstractmethod
    def algorithm_id(self) -> str:
        pass

    @abstractmethod
    def generate_keypair(self) -> Tuple[bytes, bytes]:
        """Generate (public_key, private_key)."""
        pass

    @abstractmethod
    def sign(self, private_key: bytes, message: bytes) -> bytes:
        """Sign a message."""
        pass

    @abstractmethod
    def verify(self, public_key: bytes, message: bytes, 
               signature: bytes) -> bool:
        """Verify a signature."""
        pass

class KEMScheme(ABC):
    """Algorithm-agnostic KEM interface."""

    @property
    @abstractmethod
    def algorithm_id(self) -> str:
        pass

    @abstractmethod
    def generate_keypair(self) -> Tuple[bytes, bytes]:
        pass

    @abstractmethod
    def encapsulate(self, public_key: bytes) -> Tuple[bytes, bytes]:
        """Returns (ciphertext, shared_secret)."""
        pass

    @abstractmethod
    def decapsulate(self, private_key: bytes, 
                    ciphertext: bytes) -> bytes:
        """Returns shared_secret."""
        pass

# Algorithm registry
class CryptoRegistry:
    """Registry for crypto algorithm implementations."""

    _signature_schemes: Dict[str, Type[SignatureScheme]] = {}
    _kem_schemes: Dict[str, Type[KEMScheme]] = {}

    @classmethod
    def register_signature(cls, scheme_class: Type[SignatureScheme]):
        """Register a signature scheme."""
        instance = scheme_class()
        cls._signature_schemes[instance.algorithm_id] = scheme_class

    @classmethod
    def get_signature(cls, algorithm_id: str) -> SignatureScheme:
        """Get signature scheme by algorithm ID."""
        if algorithm_id not in cls._signature_schemes:
            raise ValueError(f"Unknown algorithm: {algorithm_id}")
        return cls._signature_schemes[algorithm_id]()

    # TODO: Add KEM registration and retrieval

# Example implementation (mock)
class MockMLDSA65(SignatureScheme):
    @property
    def algorithm_id(self) -> str:
        return AlgorithmID.ML_DSA_65

    def generate_keypair(self) -> Tuple[bytes, bytes]:
        return b"public_key", b"private_key"

    def sign(self, private_key: bytes, message: bytes) -> bytes:
        return b"signature"

    def verify(self, public_key: bytes, message: bytes,
               signature: bytes) -> bool:
        return True

# Register algorithms
CryptoRegistry.register_signature(MockMLDSA65)

# Usage example
print("Crypto Agility Layer")
print("=" * 50)

signer = CryptoRegistry.get_signature(AlgorithmID.ML_DSA_65)
print(f"Using algorithm: {signer.algorithm_id}")

pk, sk = signer.generate_keypair()
